# Sanitize log messages to prevent log injection
def safe_log(message: str, *args) -> str:
    """Sanitize log output to prevent log injection attacks."""
    sanitized = message.replace('\n', '\\n').replace('\r', '\\r')
    if args:
        sanitized_args = tuple(
            str(a).replace('\n', '\\n').replace('\r', '\\r') for a in args
        )
        return sanitized % sanitized_args
    return sanitized


