# Allowlist for blob container names: lowercase alphanumeric and hyphens
CONTAINER_NAME_PATTERN = re.compile(r"^[a-z0-9]([a-z0-9\-]{1,61}[a-z0-9])?$")

# Allowlist for blob names: prevent path traversal
BLOB_NAME_PATTERN = re.compile(r"^[a-zA-Z0-9._\-/]+$")


def validate_container_name(container_name: str) -> bool:
    """Validate blob container name against Azure naming rules."""
    if not container_name or not CONTAINER_NAME_PATTERN.match(container_name):
        return False
    return True


def validate_blob_name(blob_name: str) -> bool:
    """Validate blob name to prevent path traversal and injection."""
    if not blob_name:
        return False
    if not BLOB_NAME_PATTERN.match(blob_name):
        return False
    # Prevent path traversal
    if ".." in blob_name or blob_name.startswith("/"):
        return False
    # Limit length
    if len(blob_name) > 1024:
        return False
    return True


def validate_file_extension(blob_name: str, allowed_extensions: str) -> bool:
    """Check file extension against an explicit allowlist."""
    allowed = [ext.strip().lower() for ext in allowed_extensions.split(",")]
    _, ext = os.path.splitext(blob_name)
    return ext.lower() in allowed


def validate_content_size(content: bytes, max_size: int) -> bool:
    """Validate that content does not exceed maximum allowed size."""
    return len(content) <= max_size


