# --- File Processing ---

def process_file_content(content: bytes, blob_name: str) -> Dict[str, Any]:
    """
    Process file content securely.
    
    SECURITY:
    - Content is treated as untrusted input
    - JSON parsing uses standard library (no eval/exec)
    - Results are sanitized before storage
    """
    result = {
        "blob_name": blob_name,
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "size_bytes": len(content),
        "content_hash": hashlib.sha256(content).hexdigest(),
    }

    _, ext = os.path.splitext(blob_name)
    ext = ext.lower()

    if ext == ".json":
        try:
            # Parse JSON safely - json.loads is safe against code injection
            data = json.loads(content.decode("utf-8"))
            if isinstance(data, dict):
                result["record_count"] = len(data)
                result["keys"] = list(data.keys())[:50]  # Limit output size
            elif isinstance(data, list):
                result["record_count"] = len(data)
            result["status"] = "processed"
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            result["status"] = "parse_error"
            # Don't log the actual content - it could contain sensitive data
            logger.warning(safe_log("JSON parse error for blob: %s", blob_name))

    elif ext == ".csv":
        try:
            text = content.decode("utf-8")
            lines = text.strip().split("\n")
            result["line_count"] = len(lines)
            if lines:
                # Only report header, sanitized
                header = lines[0][:500]  # Limit header length
                result["header"] = header
            result["status"] = "processed"
        except UnicodeDecodeError:
            result["status"] = "decode_error"
            logger.warning(safe_log("CSV decode error for blob: %s", blob_name))

    elif ext == ".txt":
        try:
            text = content.decode("utf-8")
            result["line_count"] = text.count("\n") + 1
            result["char_count"] = len(text)
            result["status"] = "processed"
        except UnicodeDecodeError:
            result["status"] = "decode_error"
            logger.warning(safe_log("TXT decode error for blob: %s", blob_name))
    else:
        result["status"] = "unsupported_format"

    return result


def write_to_cosmos(result: Dict[str, Any]) -> str:
    """
    Write processing result to Cosmos DB.
    
    SECURITY:
    - Uses Managed Identity (no connection strings)
    - Document ID is deterministic based on content hash to prevent duplicates
    - Input is validated before writing
    """
    container = get_cosmos_container()

    # Create a deterministic document ID
    doc_id = hashlib.sha256(
        f"{result['blob_name']}:{result['content_hash']}".encode()
    ).hexdigest()

    document = {
        "id": doc_id,
        "partitionKey": result.get("blob_name", "unknown"),
        "blobName": result.get("blob_name"),
        "processedAt": result.get("processed_at"),
        "sizeBytes": result.get("size_bytes"),
        "contentHash": result.get("content_hash"),
        "status": result.get("status"),
        "recordCount": result.get("record_count"),
        "lineCount": result.get("line_count"),
    }

    # Remove None values
    document = {k: v for k, v in document.items() if v is not None}

    container.upsert_item(body=document)
    logger.info(safe_log("Document written to Cosmos DB with id: %s", doc_id))
    return doc_id


def send_notification(result: Dict[str, Any], document_id: str) -> None:
    """
    Send processing notification via Event Grid.
    
    SECURITY:
    - Uses Managed Identity (no API keys in code)
    - Only sends metadata, never file content
    - Event data is sanitized
    """
    client = get_eventgrid_client()

    # Only include non-sensitive metadata in the event
    event_data = {
        "documentId": document_id,
        "blobName": result.get("blob_name"),
        "status": result.get("status"),
        "processedAt": result.get("processed_at"),
        "sizeBytes": result.get("size_bytes"),
        # Never include file content or sensitive data in events
    }

    event = CloudEvent(
        source="azure-function/blob-processor",
        type="BlobProcessing.Completed",
        data=event_data,
        subject=f"blobs/{result.get('blob_name', 'unknown')}",
    )

    client.send([event])
    logger.info(
        safe_log("Event Grid notification sent for blob: %s", result.get("blob_name"))
    )


