@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP trigger to manually process a specific blob.
    
    SECURITY MEASURES:
    1. Requires Function-level auth key
    2. Validates all input parameters
    3. Uses allowlists for container and file extensions
    4. Returns minimal information in responses
    """
    config = get_config()

    try:
        # Parse request body
        try:
            req_body = req.get_json()
        except ValueError:
            return func.HttpResponse(
                json.dumps({"error": "Invalid JSON in request body"}),
                status_code=400,
                mimetype="application/json",
            )

        container_name = req_body.get("container", "")
        blob_name = req_body.get("blob_name", "")

        # SECURITY: Validate container against allowlist
        allowed_container = config["ALLOWED_BLOB_CONTAINER"]
        if container_name != allowed_container:
            logger.warning(
                safe_log(
                    "HTTP request for unauthorized container: %s", container_name
                )
            )
            return func.HttpResponse(
                json.dumps({"error": "Container not allowed"}),
                status_code=403,
                mimetype="application/json",
            )

        if not validate_container_name(container_name):
            return func.HttpResponse(
                json.dumps({"error": "Invalid container name"}),
                status_code=400,
                mimetype="application/json",
            )

        # SECURITY: Validate blob name
        if not validate_blob_name(blob_name):
            return func.HttpResponse(
                json.dumps({"error": "Invalid blob name"}),
                status_code=400,
                mimetype="application/json",
            )

        # SECURITY: Validate file extension
        if not validate_file_extension(blob_name, config["ALLOWED_EXTENSIONS"]):
            return func.HttpResponse(
                json.dumps({"error": "File type not allowed"}),
                status_code=400,
                mimetype="application/json",
            )

        # Read blob using Managed Identity
        blob_service = get_blob_service_client()
        blob_client = blob_service.get_blob_client(
            container=container_name, blob=blob_name
        )

        # Check blob exists and get properties first
        try:
            properties = blob_client.get_blob_properties()
        except Exception:
            return func.HttpResponse(
                json.dumps({"error": "Blob not found"}),
                status_code=404,
                mimetype="application/json",
            )

        # SECURITY: Check size before downloading
        max_size = int(config["MAX_FILE_SIZE_BYTES"])
        if properties.size and properties.size > max_size:
            return func.HttpResponse(
                json.dumps({"error": "Blob exceeds maximum allowed size"}),
                status_code=413,
                mimetype="application/json",
            )

        # Download and process
        download_stream = blob_client.download_blob()
        content = download_stream.readall()

        if not validate_content_size(content, max_size):
            return func.HttpResponse(
                json.dumps({"error": "Blob exceeds maximum allowed size"}),
                status_code=413,
                mimetype="application/json",
            )

        result = process_file_content(content, blob_name)
        document_id = write_to_cosmos(result)
        send_notification(result, document_id)

        # Return minimal response - no sensitive data
        response = {
            "documentId": document_id,
            "status": result.get("status"),
            "processedAt": result.get("processed_at"),
        }

        return func.HttpResponse(
            json.dumps(response),
            status_code=200,
            mimetype="application/json",
        )

    except Exception as e:
        logger.error(
            safe_log("Error in HTTP trigger: %s", type(e).__name__)
        )
        # SECURITY: Never expose internal error details to clients
        return func.HttpResponse(
            json.dumps({"error": "Internal processing error"}),
            status_code=500,
            mimetype="application/json",
        )


